// oidc-spa/src/context/AuthContext.js
import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import oidcService from '../services/oidcService';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);
  const refreshTimerRef = useRef(null);

  // Setup automatic token refresh
  const setupTokenRefresh = useCallback(() => {
    if (refreshTimerRef.current) {
      clearTimeout(refreshTimerRef.current);
    }

    const expiresAt = sessionStorage.getItem('oidc_spa_token_expires_at');
    if (expiresAt) {
      const expiresIn = parseInt(expiresAt, 10) - Date.now();
      // Refresh 60 seconds before expiry
      const refreshIn = Math.max(expiresIn - 60000, 0);

      refreshTimerRef.current = setTimeout(async () => {
        try {
          await oidcService.refreshToken();
          const updatedUser = oidcService.getUserProfile();
          setUser(updatedUser);
          setupTokenRefresh();
        } catch (err) {
          console.error('Token refresh failed:', err);
          setUser(null);
          setIsAuthenticated(false);
          setError('Session expired. Please log in again.');
        }
      }, refreshIn);
    }
  }, []);

  // Initialize auth state on mount
  useEffect(() => {
    const initAuth = () => {
      try {
        if (oidcService.isAuthenticated()) {
          const userProfile = oidcService.getUserProfile();
          setUser(userProfile);
          setIsAuthenticated(true);
          setupTokenRefresh();
        }
      } catch (err) {
        console.error('Auth initialization error:', err);
        setError(err.message);
      } finally {
        setIsLoading(false);
      }
    };

    initAuth();

    return () => {
      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }
    };
  }, [setupTokenRefresh]);

  const login = useCallback(async (additionalParams = {}) => {
    setIsLoading(true);
    setError(null);
    try {
      await oidcService.login(additionalParams);
    } catch (err) {
      setError(err.message);
      setIsLoading(false);
    }
  }, []);

  const handleCallback = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const result = await oidcService.handleCallback();
      setUser(result.user);
      setIsAuthenticated(true);
      setupTokenRefresh();
      return result;
    } catch (err) {
      setError(err.message);
      setUser(null);
      setIsAuthenticated(false);
      throw err;
    } finally {
      setIsLoading(false);
    }
  }, [setupTokenRefresh]);

  const logout = useCallback(async () => {
    if (refreshTimerRef.current) {
      clearTimeout(refreshTimerRef.current);
    }
    setIsLoading(true);
    try {
      await oidcService.logout();
    } catch (err) {
      // Logout should always clear local state even on error
      setUser(null);
      setIsAuthenticated(false);
      setError(err.message);
      setIsLoading(false);
    }
  }, []);

  const getAccessToken = useCallback(() => {
    return oidcService.getAccessToken();
  }, []);

  const value = {
    user,
    isAuthenticated,
    isLoading,
    error,
    login,
    handleCallback,
    logout,
    getAccessToken,
    clearError: () => setError(null)
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

export default AuthContext;

// oidc-spa/src/components/ProtectedRoute.js
import React from 'react';
import { useAuth } from '../context/AuthContext';

function ProtectedRoute({ children, fallback }) {
  const { isAuthenticated, isLoading, login } = useAuth();

  if (isLoading) {
    return (
      fallback || (
        <div style={styles.container}>
          <div style={styles.spinner}></div>
          <p>Checking authentication...</p>
        </div>
      )
    );
  }

  if (!isAuthenticated) {
    return (
      <div style={styles.container}>
        <div style={styles.card}>
          <h2>Authentication Required</h2>
          <p>You need to be logged in to access this page.</p>
          <button style={styles.loginButton} onClick={() => login()}>
            Log In
          </button>
        </div>
      </div>
    );
  }

  return children;
}

