import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';

function CallbackHandler({ onSuccess, onError }) {
  const { handleCallback, error: authError } = useAuth();
  const [status, setStatus] = useState('processing');
  const [error, setError] = useState(null);

  useEffect(() => {
    let mounted = true;

    const processCallback = async () => {
      try {
        const result = await handleCallback();
        if (mounted) {
          setStatus('success');
          if (onSuccess) {
            onSuccess(result);
          }
        }
      } catch (err) {
        if (mounted) {
          setStatus('error');
          setError(err.message);
          if (onError) {
            onError(err);
          }
        }
      }
    };

    processCallback();

    return () => {
      mounted = false;
    };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const displayError = error || authError;

  if (status === 'processing') {
    return (
      <div style={styles.container}>
        <div style={styles.card}>
          <div style={styles.spinnerContainer}>
            <div style={styles.spinner}></div>
          </div>
          <h2 style={styles.title}>Completing Sign In</h2>
          <p style={styles.subtitle}>Please wait while we verify your identity...</p>
        </div>
      </div>
    );
  }

  if (status === 'error') {
    return (
      <div style={styles.container}>
        <div style={styles.errorCard}>
          <div style={styles.errorIcon}>⚠️</div>
          <h2 style={styles.title}>Authentication Failed</h2>
          <p style={styles.errorMessage}>{displayError}</p>
          <button
            style={styles.retryButton}
            onClick={() => (window.location.href = '/')}
          >
            Return to Home
          </button>
        </div>
      </div>
    );
  }

  if (status === 'success') {
    return (
      <div style={styles.container}>
        <div style={styles.card}>
          <div style={styles.successIcon}>✓</div>
          <h2 style={styles.title}>Sign In Successful</h2>
          <p style={styles.subtitle}>Redirecting...</p>
        </div>
      </div>
    );
  }

  return null;
}

