// oidc-spa/src/components/UserProfile.js
import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { decodeJwt } from '../utils/tokenUtils';
import SecureStorage from '../utils/storageUtils';

function UserProfile() {
  const { user, logout, getAccessToken } = useAuth();
  const [showTokenDetails, setShowTokenDetails] = useState(false);
  const [tokenInfo, setTokenInfo] = useState(null);

  if (!user) {
    return null;
  }

  const handleShowTokenDetails = () => {
    if (!showTokenDetails) {
      const idToken = SecureStorage.getItem('id_token');
      if (idToken) {
        try {
          const decoded = decodeJwt(idToken);
          setTokenInfo(decoded);
        } catch (e) {
          setTokenInfo({ error: e.message });
        }
      }
    }
    setShowTokenDetails(!showTokenDetails);
  };

  return (
    <div style={styles.container}>
      <div style={styles.profileCard}>
        <div style={styles.header}>
          {user.picture ? (
            <img
              src={user.picture}
              alt={user.name}
              style={styles.avatar}
              referrerPolicy="no-referrer"
            />
          ) : (
            <div style={styles.avatarPlaceholder}>
              {user.name?.charAt(0)?.toUpperCase() || '?'}
            </div>
          )}
          <div style={styles.userInfo}>
            <h2 style={styles.name}>{user.name}</h2>
            {user.email && (
              <p style={styles.email}>
                {user.email}
                {user.emailVerified && (
                  <span style={styles.verifiedBadge} title="Email verified">
                    ✓
                  </span>
                )}
              </p>
            )}
          </div>
        </div>

        <div style={styles.details}>
          <div style={styles.detailRow}>
            <span style={styles.detailLabel}>Subject ID</span>
            <span style={styles.detailValue}>{user.sub}</span>
          </div>
          {user.givenName && (
            <div style={styles.detailRow}>
              <span style={styles.detailLabel}>Given Name</span>
              <span style={styles.detailValue}>{user.givenName}</span>
            </div>
          )}
          {user.familyName && (
            <div style={styles.detailRow}>
              <span style={styles.detailLabel}>Family Name</span>
              <span style={styles.detailValue}>{user.familyName}</span>
            </div>
          )}
          {user.locale && (
            <div style={styles.detailRow}>
              <span style={styles.detailLabel}>Locale</span>
              <span style={styles.detailValue}>{user.locale}</span>
            </div>
          )}
        </div>

        <div style={styles.actions}>
          <button style={styles.detailsButton} onClick={handleShowTokenDetails}>
            {showTokenDetails ? 'Hide' : 'Show'} Token Details
          </button>
          <button style={styles.logoutButton} onClick={logout}>
            Sign Out
          </button>
        </div>

        {showTokenDetails && tokenInfo && (
          <div style={styles.tokenSection}>
            <h3 style={styles.tokenTitle}>ID Token Details</h3>
            {tokenInfo.error ? (
              <p style={styles.tokenError}>{tokenInfo.error}</p>
            ) : (
              <>
                <div style={styles.tokenBlock}>
                  <h4 style={styles.tokenSubtitle}>Header</h4>
                  <pre style={styles.tokenPre}>
                    {JSON.stringify(tokenInfo.header, null, 2)}
                  </pre>
                </div>
                <div style={styles.tokenBlock}>
                  <h4 style={styles.tokenSubtitle}>Payload</h4>
                  <pre style={styles.tokenPre}>
                    {JSON.stringify(tokenInfo.payload, null, 2)}
                  </pre>
                </div>
                <div style={styles.tokenBlock}>
                  <h4 style={styles.tokenSubtitle}>Token Timestamps</h4>
                  <div style={styles.detailRow}>
                    <span style={styles.detailLabel}>Issued At</span>
                    <span style={styles.detailValue}>
                      {tokenInfo.payload.iat
                        ? new Date(tokenInfo.payload.iat * 1000).toLocaleString()
                        : 'N/A'}
                    </span>
                  </div>
                  <div style={styles.detailRow}>
                    <span style={styles.detailLabel}>Expires At</span>
                    <span style={styles.detailValue}>
                      {tokenInfo.payload.exp
                        ? new Date(tokenInfo.payload.exp * 1000).toLocaleString()
                        : 'N/A'}
                    </span>
                  </div>
                </div>
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

