// oidc-spa/src/pages/DashboardPage.js
import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';

function DashboardPage() {
  const { user, getAccessToken } = useAuth();
  const [apiResponse, setApiResponse] = useState(null);
  const [apiLoading, setApiLoading] = useState(false);
  const [apiError, setApiError] = useState(null);

  const callProtectedApi = async () => {
    setApiLoading(true);
    setApiError(null);
    setApiResponse(null);

    try {
      const token = getAccessToken();
      if (!token) {
        throw new Error('No access token available');
      }

      // Example API call with Bearer token
      // Replace with your actual API endpoint
      const response = await fetch('https://api.example.com/userinfo', {
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        throw new Error(`API responded with ${response.status}: ${response.statusText}`);
      }

      const data = await response.json();
      setApiResponse(data);
    } catch (err) {
      setApiError(err.message);
      // For demo purposes, show a mock response
      setApiResponse({
        demo: true,
        message: 'This is a demo response. Configure a real API endpoint to see actual data.',
        user: user?.sub,
        timestamp: new Date().toISOString()
      });
    } finally {
      setApiLoading(false);
    }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>Dashboard</h1>
      <p style={styles.subtitle}>Protected content - only visible to authenticated users</p>

      <div style={styles.grid}>
        <div style={styles.card}>
          <h3 style={styles.cardTitle}>👤 User Info</h3>
          <div style={styles.infoList}>
            <div style={styles.infoItem}>
              <span style={styles.infoLabel}>Name</span>
              <span style={styles.infoValue}>{user?.name || 'N/A'}</span>
            </div>
            <div style={styles.infoItem}>
              <span style={styles.infoLabel}>Email</span>
              <span style={styles.infoValue}>{user?.email || 'N/A'}</span>
            </div>
            <div style={styles.infoItem}>
              <span style={styles.infoLabel}>Subject</span>
              <span style={styles.infoValue}>{user?.sub || 'N/A'}</span>
            </div>
          </div>
        </div>

        <div style={styles.card}>
          <h3 style={styles.cardTitle}>🔑 Token Status</h3>
          <div style={styles.infoList}>
            <div style={styles.infoItem}>
              <span style={styles.infoLabel}>Access Token</span>
              <span style={{ ...styles.infoValue, color: getAccessToken() ? '#38a169' : '#e53e3e' }}>
                {getAccessToken() ? '✓ Valid' : '✗ Expired/Missing'}
              </span>
            </div>
            <div style={styles.infoItem}>
              <span style={styles.infoLabel}>Token Type</span>
              <span style={styles.infoValue}>Bearer</span>
            </div>
          </div>
        </div>

        <div style={{ ...styles.card, gridColumn: '1 / -1' }}>
          <h3 style={styles.cardTitle}>🌐 API Test</h3>
          <p style={styles.apiDescription}>
            Test calling a protected API endpoint with your access token.
          </p>
          <button
            style={styles.apiButton}
            onClick={callProtectedApi}
            disabled={apiLoading}
          >
            {apiLoading ? 'Calling API...' : 'Call Protected API'}
          </button>

          {apiError && (
            <div style={styles.apiError}>
              <strong>Note:</strong> {apiError}
            </div>
          )}

          {apiResponse && (
            <div style={styles.apiResponseContainer}>
              <h4 style={styles.responseTitle}>Response:</h4>
              <pre style={styles.apiResponsePre}>
                {JSON.stringify(apiResponse, null, 2)}
              </pre>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

